using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a new sketch on the xy plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xyPlane = rootComp->xYConstructionPlane();
    if (!xyPlane)
        return false;
    Ptr sketch = sketches->add(xyPlane);
    if (!sketch)
        return false;

    // Draw two connected lines.
    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;
    Ptr lines = curves->sketchLines();
    if (!lines)
        return false;
    Ptr line1 =
        lines->addByTwoPoints(adsk::core::Point3D::create(0, 0, 0), adsk::core::Point3D::create(3, 1, 0));
    if (!line1)
        return false;
    Ptr line2 = lines->addByTwoPoints(line1->endSketchPoint(), adsk::core::Point3D::create(1, 4, 0));
    if (!line2)
        return false;

    // Add a fillet.
    Ptr arcs = curves->sketchArcs();
    if (!arcs)
        return false;
    Ptr arc =
        arcs->addFillet(line1, line1->endSketchPoint()->geometry(), line2, line2->startSketchPoint()->geometry(), 1);
    if (!arc)
        return false;

    // Add the geometry to a collection. This uses a utility function that
    // automatically finds the connected curves and returns a collection.
    Ptr connectedCurves = sketch->findConnectedCurves(line1);
    if (!connectedCurves)
        return false;

    // Create the offset.
    Ptr dirPoint = adsk::core::Point3D::create(0, 0.5, 0);
    if (!dirPoint)
        return false;
    Ptr offsetCurves = sketch->offset(connectedCurves, dirPoint, 0.25);
    if (!offsetCurves)
        return false;

    return true;
}
